The issue here is that you've manually allocated memory for a `DataBuffer` object using `new`, but you're not updating any pointers to keep track of this allocation. 

Instead of manually managing the memory through pointers, consider using a smart pointer like `std::unique_ptr` or `std::shared_ptr` to automatically handle memory deallocation for you. 

Here's how you can refactor your code to use `std::unique_ptr`:

```cpp
#include <iostream>
#include <memory>

class DataBuffer {
public:
    DataBuffer(int size) {
        buffer = std::make_unique<int[]>(size);
        std::cout << "Buffer allocated" << std::endl;
    }
    ~DataBuffer() {
        // destructor logic
    }
    void process() {
        std::cout << "Processing data..." << std::endl;
    }
private:
    std::unique_ptr<int[]> buffer;
};

void runTask() {
    DataBuffer task(1024);
    task.process();
}

int main() {
    for(int i = 0; i < 1000; i++) {
        runTask();
    }
    return 0;
}
```

